import React, { useState } from 'react'
import { useParams, Link } from 'react-router-dom'
import { useQuery, useAction, getTeamTasks, createTask } from 'wasp/client/operations'

export const TeamPage = () => {
  const { id } = useParams<{ id: string }>()
  const teamId = parseInt(id || '0')
  const { data: tasks, isLoading, error } = useQuery(getTeamTasks, { teamId })
  const createTaskAction = useAction(createTask)
  const [taskDesc, setTaskDesc] = useState('')

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!taskDesc) return
    try {
      await createTaskAction({ teamId, description: taskDesc })
      setTaskDesc('')
    } catch (err: any) {
      alert('Error adding task: ' + err.message)
    }
  }

  if (isLoading) return 'Loading tasks...'
  if (error) return 'Error: ' + error.message

  return (
    <div style={{ padding: '1rem' }}>
      <header style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
        <Link to="/">Back to Dashboard</Link>
        <h1>Team Tasks</h1>
      </header>

      <form onSubmit={handleAddTask} style={{ marginBottom: '2rem' }}>
        <input
          type="text"
          placeholder="Task description"
          value={taskDesc}
          onChange={(e) => setTaskDesc(e.target.value)}
        />
        <button type="submit">Add Task</button>
      </form>

      <ul>
        {tasks?.map((task) => (
          <li key={task.id}>
            <span style={{ textDecoration: task.isDone ? 'line-through' : 'none' }}>
              {task.description}
            </span>
          </li>
        ))}
      </ul>
    </div>
  )
}

